const { subtle } = require('crypto').webcrypto;

// ── CONFIG ──────────────────────────────────────────────
const ROOT_FOLDER_ID = $env.GOOGLE_PROJECT_FOLDER;
const serviceAccountEmail = $env.GOOGLE_SERVICE_ACCOUNT;
const privateKey = $env.GOOGLE_SERVICE_ACCOUNT_KEY.replace(/\\n/g, '\n');
const SCOPES = 'https://www.googleapis.com/auth/drive.readonly';

// ── GENERATE JWT ─────────────────────────────────────────
function base64url(str) {
  return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}
function base64urlFromUint8(bytes) {
  let str = '';
  for (const b of bytes) str += String.fromCharCode(b);
  return base64url(str);
}

const now = Math.floor(Date.now() / 1000);
const header = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const claim  = base64url(JSON.stringify({
  iss: serviceAccountEmail,
  scope: SCOPES,
  aud: 'https://oauth2.googleapis.com/token',
  iat: now,
  exp: now + 3600
}));
const signingInput = `${header}.${claim}`;

const pemBody = privateKey.replace(/-----[^-]+-----/g, '').replace(/[^A-Za-z0-9+/=]/g, '');

const binaryDer = Uint8Array.from(atob(pemBody), c => c.charCodeAt(0));
const cryptoKey = await subtle.importKey(
  'pkcs8', binaryDer.buffer,
  { name: 'RSASSA-PKCS1-v1_5', hash: 'SHA-256' },
  false, ['sign']
);
const signature = await subtle.sign(
  'RSASSA-PKCS1-v1_5',
  cryptoKey,
  new TextEncoder().encode(signingInput)
);
const jwt = `${signingInput}.${base64urlFromUint8(new Uint8Array(signature))}`;

// ── EXCHANGE JWT FOR ACCESS TOKEN ────────────────────────
const tokenData = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`
});
const access_token = tokenData.access_token;

// ── RECURSIVE FOLDER WALK ────────────────────────────────
async function listRecursive(folderId, path) {
  let files = [];
  let pageToken = null;
  do {
    const query = `q=${encodeURIComponent(`'${folderId}' in parents and trashed = false`)}&fields=${encodeURIComponent('nextPageToken, files(id, name, mimeType)')}&pageSize=1000${pageToken ? `&pageToken=${encodeURIComponent(pageToken)}` : ''}`;

    const data = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.googleapis.com/drive/v3/files?${query}`,
      headers: { Authorization: `Bearer ${access_token}` }
    });
    for (const file of data.files) {
      const filePath = `${path}/${file.name}`;
      if (file.mimeType === 'application/vnd.google-apps.folder') {
        const children = await listRecursive(file.id, filePath);
        files = files.concat(children);
      } else {
        files.push({
          id: file.id,
          name: file.name,
          mimeType: file.mimeType,
          path: filePath
        });
      }
    }
    pageToken = data.nextPageToken;
  } while (pageToken);
  return files;
}

const allFiles = await listRecursive(ROOT_FOLDER_ID, '');
return allFiles.map(f => ({ json: f }));

const mammoth = require('mammoth');
const { subtle } = require('crypto').webcrypto;
const { execSync } = require('child_process');
const fs = require('fs');

// ── CONFIG ───────────────────────────────────────────────
const DEST_FOLDER_ID      = $env.GOOGLE_DEST_FOLDER;
const serviceAccountEmail = $env.GOOGLE_SERVICE_ACCOUNT;
const privateKey          = $env.GOOGLE_SERVICE_ACCOUNT_KEY.replace(/\\n/g, '\n');
const SCOPES              = 'https://www.googleapis.com/auth/drive';

// ── JWT + TOKEN ──────────────────────────────────────────
function base64url(str) {
  return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}
function base64urlFromUint8(bytes) {
  let str = '';
  for (const b of bytes) str += String.fromCharCode(b);
  return base64url(str);
}
const now          = Math.floor(Date.now() / 1000);
const header       = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
const claim        = base64url(JSON.stringify({
  iss: serviceAccountEmail, scope: SCOPES,
  aud: 'https://oauth2.googleapis.com/token',
  iat: now, exp: now + 3600
}));
const signingInput = `${header}.${claim}`;
const pemBody      = privateKey.replace(/-----[^-]+-----/g, '').replace(/[^A-Za-z0-9+/=]/g, '');
const binaryDer    = Uint8Array.from(atob(pemBody), c => c.charCodeAt(0));
const cryptoKey    = await subtle.importKey(
  'pkcs8', binaryDer.buffer,
  { name: 'RSASSA-PKCS1-v1_5', hash: 'SHA-256' },
  false, ['sign']
);
const signature = await subtle.sign('RSASSA-PKCS1-v1_5', cryptoKey, new TextEncoder().encode(signingInput));
const jwt       = `${signingInput}.${base64urlFromUint8(new Uint8Array(signature))}`;

const tokenData = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://oauth2.googleapis.com/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`
});
const access_token = tokenData.access_token;
const authHeader   = { Authorization: `Bearer ${access_token}` };

// ── HELPERS ───────────────────────────────────────────────
const folderCache = { '': DEST_FOLDER_ID };

async function ensureFolder(folderPath) {
  if (folderCache[folderPath]) return folderCache[folderPath];
  const parts = folderPath.split('/').filter(Boolean);
  let currentPath = '';
  let parentId    = DEST_FOLDER_ID;
  for (const part of parts) {
    currentPath += '/' + part;
    if (folderCache[currentPath]) {
      parentId = folderCache[currentPath];
      continue;
    }
    const search = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.googleapis.com/drive/v3/files?supportsAllDrives=true&includeItemsFromAllDrives=true&q=${encodeURIComponent(`name='${part}' and mimeType='application/vnd.google-apps.folder' and '${parentId}' in parents and trashed=false`)}&fields=files(id)`,
      headers: authHeader
    });
    if (search.files && search.files.length > 0) {
      parentId = search.files[0].id;
    } else {
      const created = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://www.googleapis.com/drive/v3/files?supportsAllDrives=true',
        headers: { ...authHeader, 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: part, mimeType: 'application/vnd.google-apps.folder', parents: [parentId] })
      });
      parentId = created.id;
    }
    folderCache[currentPath] = parentId;
  }
  return parentId;
}

async function deleteFile(fileId) {
  try {
    await this.helpers.httpRequest({
      method: 'DELETE',
      url: `https://www.googleapis.com/drive/v3/files/${fileId}?supportsAllDrives=true`,
      headers: authHeader
    });
  } catch (err) {
    if (!err.message.includes('404')) throw err;
  }
}

// List all files recursively in a Drive folder
async function listDestRecursive(folderId, path) {
  let files = [];
  let pageToken = null;
  do {
    const q = encodeURIComponent(`'${folderId}' in parents and trashed = false`);
    const url = `https://www.googleapis.com/drive/v3/files?supportsAllDrives=true&includeItemsFromAllDrives=true&q=${q}&fields=nextPageToken,files(id,name,mimeType)&pageSize=1000${pageToken ? `&pageToken=${encodeURIComponent(pageToken)}` : ''}`;
    const data = await this.helpers.httpRequest({ method: 'GET', url, headers: authHeader });
    for (const file of data.files) {
      const filePath = `${path}/${file.name}`;
      if (file.mimeType === 'application/vnd.google-apps.folder') {
        const children = await listDestRecursive(file.id, filePath);
        files = files.concat(children);
      } else {
        files.push({ id: file.id, name: file.name, path: filePath });
      }
    }
    pageToken = data.nextPageToken;
  } while (pageToken);
  return files;
}

// ── BUILD SOURCE FILE SET ────────────────────────────────
const sourceFiles = $input.all().map(i => i.json);
// Expected destination paths (docx → html)
const expectedDestPaths = new Set(
  sourceFiles.map(f => f.path.replace(/\.docx$/i, '.html'))
);

// ── SYNC DESTINATION ─────────────────────────────────────
// List everything currently in destination
const destFiles = await listDestRecursive(DEST_FOLDER_ID, '');

// Group destination files by path to find duplicates
const destByPath = {};
for (const f of destFiles) {
  if (!destByPath[f.path]) destByPath[f.path] = [];
  destByPath[f.path].push(f);
}

const deleteLog = [];

// (1) Delete duplicates — keep first, delete the rest
for (const [path, instances] of Object.entries(destByPath)) {
  if (instances.length > 1) {
    for (const dup of instances.slice(1)) {
      await deleteFile(dup.id);
      deleteLog.push({ action: 'deleted_duplicate', path, id: dup.id });
    }
  }
}

// (2) Delete destination files with no corresponding source file
for (const [path, instances] of Object.entries(destByPath)) {
  if (!expectedDestPaths.has(path)) {
    await deleteFile(instances[0].id);
    deleteLog.push({ action: 'deleted_orphan', path, id: instances[0].id });
  }
}

// ── PROCESS SOURCE FILES ──────────────────────────────────
const results = [];

for (const file of sourceFiles) {
  const tmpFile = `/tmp/n8n_${file.id}.docx`;
  let step = 'check';
  try {
    const folderPath   = file.path.substring(0, file.path.lastIndexOf('/'));
    const destFolderId = await ensureFolder(folderPath);
    const fileName     = file.name.replace(/\.docx$/i, '.html');
    const destPath     = `/${folderPath.split('/').filter(Boolean).join('/')}/${fileName}`;

    // Skip if already exists (after dedup, at most one remains)
    const existing = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.googleapis.com/drive/v3/files?supportsAllDrives=true&includeItemsFromAllDrives=true&q=${encodeURIComponent(`name='${fileName}' and '${destFolderId}' in parents and trashed=false`)}&fields=files(id,name)`,
      headers: authHeader
    });
    if (existing.files && existing.files.length > 0) {
      results.push({ json: { sourceId: file.id, sourcePath: file.path, destId: existing.files[0].id, destName: fileName, skipped: true, reason: 'already exists' } });
      continue;
    }

    step = 'download';
    execSync(`wget -q -O "${tmpFile}" --header="Authorization: Bearer ${access_token}" --header="Accept-Encoding: identity" "https://www.googleapis.com/drive/v3/files/${file.id}?alt=media"`);

    step = 'mammoth';
    const buf = fs.readFileSync(tmpFile);
    const { value: html } = await mammoth.convertToHtml({ buffer: buf });

    step = 'upload';
    const boundary = '-------314159265358979323846';
    const metadata  = JSON.stringify({ name: fileName, parents: [destFolderId] });
    const multipartBody =
      `--${boundary}\r\nContent-Type: application/json\r\n\r\n${metadata}\r\n` +
      `--${boundary}\r\nContent-Type: text/html\r\n\r\n${html}\r\n` +
      `--${boundary}--`;

    const uploaded = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name&supportsAllDrives=true',
      headers: { ...authHeader, 'Content-Type': `multipart/related; boundary="${boundary}"` },
      body: multipartBody
    });

    results.push({ json: { sourceId: file.id, sourcePath: file.path, destId: uploaded.id, destName: uploaded.name } });
  } catch (err) {
    results.push({ json: { sourceId: file.id, sourcePath: file.path, step, error: err.message + ' (line ' + (err.stack?.match(/:(\d+):\d+\)/)?.[1] ?? '?') + ')', skipped: true } });
  } finally {
    if (fs.existsSync(tmpFile)) fs.unlinkSync(tmpFile);
  }
}

return [...results, ...deleteLog.map(d => ({ json: d }))];
